class AnimatedCharacter extends cc.Node {
    private _sprite: cc.Sprite;
    private _idleAction: cc.Action;
    private _runAction: cc.Action;
    private _currentAnim: string = '';

    constructor(atlasPath: string, atlasImage: string) {
        super();
        cc.spriteFrameCache.addSpriteFrames(atlasPath, atlasImage);

        const idleFrame = cc.spriteFrameCache.getSpriteFrame('hero_idle_01.png');
        this._sprite = new cc.Sprite(idleFrame);
        this.addChild(this._sprite);

        this._idleAction = this.createAnim('hero_idle', 4, 0.15);
        this._runAction = this.createAnim('hero_run', 8, 0.08);

        this.playIdle();
    }

    private createAnim(prefix: string, count: number, delay: number): cc.Action {
        const frames: cc.SpriteFrame[] = [];
        for (let i = 1; i <= count; i++) {
            const name = prefix + '_' + (i < 10 ? '0' : '') + i + '.png';
            frames.push(cc.spriteFrameCache.getSpriteFrame(name));
        }
        const anim = new cc.Animation(frames, delay);
        return cc.animate(anim).repeatForever();
    }

    playIdle(): void {
        if (this._currentAnim === 'idle') return;
        this._currentAnim = 'idle';
        this._sprite.stopAllActions();
        this._sprite.runAction(this._idleAction.clone());
    }

    playRun(): void {
        if (this._currentAnim === 'run') return;
        this._currentAnim = 'run';
        this._sprite.stopAllActions();
        this._sprite.runAction(this._runAction.clone());
    }

    setFacing(right: boolean): void {
        this._sprite.setFlippedX(!right);
    }
}

// Usage:
const hero = new AnimatedCharacter('res/hero.plist', 'res/hero.png');
hero.setPosition(240, 160);
this.addChild(hero);
hero.playRun();
hero.setFacing(false); // face left
```

