class ParallaxBG extends cc.Node {
    private _layers: Array<{ sprites: cc.Sprite[]; speed: number }> = [];

    addLayer(texturePath: string, speed: number, zOrder: number): void {
        const winSize = cc.director.getWinSize();
        cc.textureCache.addImage(texturePath);
        const tex = cc.textureCache.getTextureForKey(texturePath);
        const texW = tex.getContentSize().width;

        // Create enough sprites to tile across screen + buffer
        const count = Math.ceil(winSize.width / texW) + 2;
        const sprites: cc.Sprite[] = [];

        for (let i = 0; i < count; i++) {
            const s = new cc.Sprite(tex);
            s.setAnchorPoint(cc.p(0, 0));
            s.setPosition(i * texW, 0);
            this.addChild(s, zOrder);
            sprites.push(s);
        }

        this._layers.push({ sprites, speed });
    }

    scroll(dx: number): void {
        for (const layer of this._layers) {
            const texW = layer.sprites[0].getContentSize().width;
            for (const s of layer.sprites) {
                s.setPositionX(s.getPositionX() - dx * layer.speed);
                // Wrap around
                if (s.getPositionX() + texW < 0) {
                    const maxX = Math.max(...layer.sprites.map(sp => sp.getPositionX()));
                    s.setPositionX(maxX + texW);
                }
            }
        }
    }
}

// Usage:
const bg = new ParallaxBG();
this.addChild(bg, -10);
bg.addLayer('res/bg_sky.png', 0.2, 0);     // slow
bg.addLayer('res/bg_mountains.png', 0.5, 1); // medium
bg.addLayer('res/bg_trees.png', 1.0, 2);    // full speed

// In update:
update(dt: number): void {
    bg.scroll(100 * dt);
}
```

