    const cs = cornerSize;
    const w = totalSize.width;
    const h = totalSize.height;
    const tx = texRect.x;
    const ty = texRect.y;
    const tw = texRect.width;
    const th = texRect.height;

    // Helper to create a sprite from a sub-rect of the texture
    function makeSlice(sx: number, sy: number, sw: number, sh: number): cc.Sprite {
        const frame = new cc.SpriteFrame(tex, cc.rect(tx + sx, ty + sy, sw, sh));
        return new cc.Sprite(frame);
    }

    // Bottom-left corner
    const bl = makeSlice(0, th - cs, cs, cs);
    bl.setAnchorPoint(cc.p(0, 0));
    bl.setPosition(0, 0);
    container.addChild(bl);

    // Bottom-right corner
    const br = makeSlice(tw - cs, th - cs, cs, cs);
    br.setAnchorPoint(cc.p(0, 0));
    br.setPosition(w - cs, 0);
    container.addChild(br);

    // Top-left corner
    const tl = makeSlice(0, 0, cs, cs);
    tl.setAnchorPoint(cc.p(0, 0));
    tl.setPosition(0, h - cs);
    container.addChild(tl);

    // Top-right corner
    const tr = makeSlice(tw - cs, 0, cs, cs);
    tr.setAnchorPoint(cc.p(0, 0));
    tr.setPosition(w - cs, h - cs);
    container.addChild(tr);

    // Edges (stretched)
    const top = makeSlice(cs, 0, tw - cs * 2, cs);
    top.setAnchorPoint(cc.p(0, 0));
    top.setPosition(cs, h - cs);
    top.setScaleX((w - cs * 2) / (tw - cs * 2));
    container.addChild(top);

    const bottom = makeSlice(cs, th - cs, tw - cs * 2, cs);
    bottom.setAnchorPoint(cc.p(0, 0));
    bottom.setPosition(cs, 0);
    bottom.setScaleX((w - cs * 2) / (tw - cs * 2));
    container.addChild(bottom);

    return container;
}
```

instruction:
Find and fix the bug in this sprite creation code:

```typescript
const sprite = cc.Sprite.create();
sprite.setTexture('res/hero.png');
sprite.setPosition(240, 160);
this.addChild(sprite);
```

output:
This code may appear to work, but the issue is that creating an empty sprite with `cc.Sprite.create()` and then calling `setTexture` does not automatically set the content size. The sprite may have zero dimensions.

The recommended approach is to pass the texture at creation time:

Fixed code:
```typescript
const sprite = cc.Sprite.create('res/hero.png');
sprite.setPosition(240, 160);
this.addChild(sprite);
```

Or if you must use two-step initialization:
```typescript
const sprite = new cc.Sprite();
sprite.initWithFile('res/hero.png');  // properly initializes texture + size
sprite.setPosition(240, 160);
this.addChild(sprite);
```

Using `initWithFile` (or passing the path to the constructor) ensures the sprite's content size, texture rect, and other properties are all set correctly.

