```typescript
class AtlasManager {
    private _loaded: Map<string, string> = new Map(); // plist -> texture

    load(plistPath: string, texturePath: string): void {
        if (this._loaded.has(plistPath)) return;
        cc.spriteFrameCache.addSpriteFrames(plistPath, texturePath);
        this._loaded.set(plistPath, texturePath);
    }

    unload(plistPath: string): void {
        const texPath = this._loaded.get(plistPath);
        if (!texPath) return;
        cc.spriteFrameCache.removeSpriteFramesFromFile(plistPath);
        cc.textureCache.removeTextureForKey(texPath);
        this._loaded.delete(plistPath);
    }

    unloadAll(): void {
        for (const [plist, tex] of this._loaded) {
            cc.spriteFrameCache.removeSpriteFramesFromFile(plist);
            cc.textureCache.removeTextureForKey(tex);
        }
        this._loaded.clear();
    }

    isLoaded(plistPath: string): boolean {
        return this._loaded.has(plistPath);
    }

    cleanup(): void {
        cc.spriteFrameCache.removeUnusedSpriteFrames();
        cc.textureCache.removeUnusedTextures();
    }

    getLoadedCount(): number {
        return this._loaded.size;
    }
}

// Usage:
const atlasManager = new AtlasManager();
atlasManager.load('res/level1.plist', 'res/level1.png');
atlasManager.load('res/ui.plist', 'res/ui.png');

// When changing levels
atlasManager.unload('res/level1.plist');
atlasManager.load('res/level2.plist', 'res/level2.png');

// Full cleanup on scene exit
atlasManager.unloadAll();
```

