class HighlightableSprite extends cc.Node {
    private _sprite: cc.Sprite;
    private _highlight: cc.DrawNode;
    private _highlighted: boolean = false;
    private _time: number = 0;

    constructor(frameName: string) {
        super();
        this._sprite = new cc.Sprite(cc.spriteFrameCache.getSpriteFrame(frameName));
        this.addChild(this._sprite);

        this._highlight = new cc.DrawNode();
        this._highlight.setVisible(false);
        this.addChild(this._highlight, 1);

        this.scheduleUpdate();
    }

    setHighlighted(value: boolean): void {
        this._highlighted = value;
        this._highlight.setVisible(value);
        if (!value) this._highlight.clear();
    }

    update(dt: number): void {
        if (!this._highlighted) return;
        this._time += dt;
        this._highlight.clear();

        const size = this._sprite.getContentSize();
        const pad = 4 + Math.sin(this._time * 5) * 2;
        const hw = size.width / 2 + pad;
        const hh = size.height / 2 + pad;
        const alpha = Math.floor(180 + 75 * Math.sin(this._time * 4));

        this._highlight.drawRect(
            cc.p(-hw, -hh), cc.p(hw, hh),
            null, 2,
            cc.color(255, 255, 0, alpha)
        );
    }
}

// Usage:
