class TileView extends cc.Node {
    private _sprite: cc.Sprite;
    private _tileSize: cc.Size;
    private _cols: number;
    private _rows: number;

    constructor(texturePath: string, tileWidth: number, tileHeight: number) {
        super();
        this._tileSize = cc.size(tileWidth, tileHeight);

        const tex = cc.textureCache.getTextureForKey(texturePath) ||
            (cc.textureCache.addImage(texturePath), cc.textureCache.getTextureForKey(texturePath));

        const texSize = tex.getContentSize();
        this._cols = Math.floor(texSize.width / tileWidth);
        this._rows = Math.floor(texSize.height / tileHeight);

        this._sprite = new cc.Sprite(tex, cc.rect(0, 0, tileWidth, tileHeight));
        this.addChild(this._sprite);
    }

    showTile(col: number, row: number): void {
        const clampedCol = Math.max(0, Math.min(col, this._cols - 1));
        const clampedRow = Math.max(0, Math.min(row, this._rows - 1));
        this._sprite.setTextureRect(cc.rect(
            clampedCol * this._tileSize.width,
            clampedRow * this._tileSize.height,
            this._tileSize.width,
            this._tileSize.height
        ));
    }

    showTileByIndex(index: number): void {
        const col = index % this._cols;
        const row = Math.floor(index / this._cols);
        this.showTile(col, row);
    }

    getTileCount(): number {
        return this._cols * this._rows;
    }
}

