    texturePath: string,
    displaySize: cc.Size
): cc.Sprite {
    cc.textureCache.addImage(texturePath);
    const tex = cc.textureCache.getTextureForKey(texturePath);

    // Enable texture repeating
    tex.setTexParameters(
        gl.LINEAR,
        gl.LINEAR,
        gl.REPEAT,  // wrap S (horizontal)
        gl.REPEAT   // wrap T (vertical)
    );

    const sprite = new cc.Sprite(tex);
    // Set texture rect larger than the texture to trigger repeating
    sprite.setTextureRect(cc.rect(0, 0, displaySize.width, displaySize.height));

    return sprite;
}

// Usage: create a repeating water texture across 480x100
const water = createRepeatingSprite('res/water_tile.png', cc.size(480, 100));
water.setAnchorPoint(cc.p(0, 0));
water.setPosition(0, 0);
this.addChild(water);
```

Note: Texture repeat via `gl.REPEAT` requires the texture dimensions to be power-of-two (e.g., 64x64, 128x128). Non-power-of-two textures must use `gl.CLAMP_TO_EDGE`.

```typescript
// 1. Load the atlas
cc.spriteFrameCache.addSpriteFrames('res/enemies.plist', 'res/enemies.png');

// 2. Create batch node with the SAME texture
const batch = new cc.SpriteBatchNode('res/enemies.png', 200);
this.addChild(batch);

// 3. Create sprites using cached frames and add to batch
function spawnEnemy(batch: cc.SpriteBatchNode, frameName: string, pos: cc.Point): cc.Sprite {
    const frame = cc.spriteFrameCache.getSpriteFrame(frameName);
    const sprite = new cc.Sprite(frame);
    sprite.setPosition(pos);
    batch.addChild(sprite);
    return sprite;
}

// All these sprites render in ONE draw call
for (let i = 0; i < 100; i++) {
    spawnEnemy(
        batch,
        'goblin.png',
        cc.p(Math.random() * 480, Math.random() * 320)
    );
}
```

Key rules:
- All sprites in the batch must use the same texture file
- Frame names must be from the same atlas
- The batch texture path must match the atlas texture
- Second constructor parameter is initial capacity (hint for allocation)

```typescript
// Get the sprite's index within the batch node's texture atlas
const index: number = sprite.getAtlasIndex();

// Set the atlas index (controls draw order within the batch)
sprite.setAtlasIndex(5);

// Get the texture atlas object
const atlas: cc.TextureAtlas = sprite.getTextureAtlas();
```

The atlas index determines the draw order of sprites within a `cc.SpriteBatchNode`. Lower indices are drawn first (behind higher indices).

In practice, these methods are rarely used directly — the batch node manages indices automatically based on z-order. They're mainly useful for:
- Custom rendering optimizations
- Debugging batch node rendering order
- Advanced sprite sorting within a batch

```typescript
const batch = new cc.SpriteBatchNode('res/atlas.png');
this.addChild(batch);

const s1 = new cc.Sprite(cc.spriteFrameCache.getSpriteFrame('bg.png'));
const s2 = new cc.Sprite(cc.spriteFrameCache.getSpriteFrame('fg.png'));
batch.addChild(s1, 0);  // z-order 0
batch.addChild(s2, 1);  // z-order 1

// Atlas indices are managed by the batch node
cc.log('s1 atlas index:', s1.getAtlasIndex());
cc.log('s2 atlas index:', s2.getAtlasIndex());
```

