```typescript
class CrossfadeSprite extends cc.Node {
    private _spriteA: cc.Sprite;
    private _spriteB: cc.Sprite;

    constructor(textureA: string, textureB: string) {
        super();
        this._spriteA = new cc.Sprite(textureA);
        this._spriteB = new cc.Sprite(textureB);
        this._spriteB.setOpacity(0);
        this.addChild(this._spriteA, 0);
        this.addChild(this._spriteB, 1);
    }

    crossfade(duration: number, onComplete?: () => void): void {
        this._spriteA.stopAllActions();
        this._spriteB.stopAllActions();

        this._spriteA.runAction(cc.fadeOut(duration));

        const fadeIn = cc.fadeIn(duration);
        if (onComplete) {
            this._spriteB.runAction(cc.sequence(fadeIn, cc.callFunc(onComplete)));
        } else {
            this._spriteB.runAction(fadeIn);
        }
    }

    swap(): void {
        const temp = this._spriteA;
        this._spriteA = this._spriteB;
        this._spriteB = temp;
        this._spriteA.setOpacity(255);
        this._spriteB.setOpacity(0);
    }
}

// Usage:
const cf = new CrossfadeSprite('res/day.png', 'res/night.png');
cf.setPosition(240, 160);
this.addChild(cf);
cf.crossfade(2.0, () => cc.log('Crossfade done'));
```

instruction:
Find and fix the bug in this sprite batch code:

```typescript
cc.spriteFrameCache.addSpriteFrames('res/atlas.plist', 'res/atlas.png');
const batch = new cc.SpriteBatchNode('res/atlas.png');
this.addChild(batch);

for (let i = 0; i < 50; i++) {
    const s = new cc.Sprite('res/enemy.png');
    batch.addChild(s);
}
```

output:
The bug is that sprites are created from a standalone file ('res/enemy.png') instead of from the atlas. Sprites in a SpriteBatchNode must use the same texture as the batch node.

Fixed code:
```typescript
cc.spriteFrameCache.addSpriteFrames('res/atlas.plist', 'res/atlas.png');
const batch = new cc.SpriteBatchNode('res/atlas.png');
this.addChild(batch);

for (let i = 0; i < 50; i++) {
    // Use sprite frame from the atlas, not a separate file
    const s = new cc.Sprite(cc.spriteFrameCache.getSpriteFrame('enemy.png'));
    s.setPosition(Math.random() * 480, Math.random() * 320);
    batch.addChild(s);
}
```

The sprite frame 'enemy.png' must be defined in 'res/atlas.plist' and its pixels must come from 'res/atlas.png'.

```typescript
function flashSprite(sprite: cc.Sprite, flashColor: cc.Color, duration: number): void {
    const originalColor = sprite.getColor();

    sprite.stopActionByTag(999);

    const tintTo = cc.tintTo(duration / 4, flashColor.r, flashColor.g, flashColor.b);
    const tintBack = cc.tintTo(duration / 4, originalColor.r, originalColor.g, originalColor.b);
    const flash = cc.sequence(
        tintTo, tintBack,
        tintTo.clone(), tintBack.clone()
    );
    flash.setTag(999);
    sprite.runAction(flash);
}

// Alternative: opacity-based flash
function blinkSprite(sprite: cc.Sprite, times: number, duration: number): void {
    sprite.stopActionByTag(998);
    const blink = cc.blink(duration, times);
    blink.setTag(998);
    sprite.runAction(blink);
}

// Usage:
flashSprite(heroSprite, cc.color(255, 0, 0), 0.5);  // red flash
blinkSprite(heroSprite, 5, 0.5);  // blink 5 times in 0.5s
```

```typescript
class LoadingScene extends cc.Scene {
    private _texturesToLoad: string[] = [
        'res/hero.png',
        'res/bg_level1.png',
        'res/enemies.png',
        'res/ui_atlas.png',
        'res/effects.png'
    ];
    private _loaded: number = 0;
    private _label: cc.LabelTTF;

    onEnter(): void {
        super.onEnter();

        this._label = new cc.LabelTTF('Loading 0%', 'Arial', 24);
        this._label.setPosition(240, 160);
        this.addChild(this._label);

        this.loadNextTexture();
    }

    private loadNextTexture(): void {
        if (this._loaded >= this._texturesToLoad.length) {
            this.onLoadComplete();
            return;
        }

        const path = this._texturesToLoad[this._loaded];
        cc.textureCache.addImage(path);
        this._loaded++;

        const pct = Math.floor((this._loaded / this._texturesToLoad.length) * 100);
        this._label.setString('Loading ' + pct + '%');

        // Process next on next frame to allow UI update
        this.scheduleOnce(() => this.loadNextTexture(), 0);
    }

    private onLoadComplete(): void {
        // All textures cached, create sprites instantly
        const tex = cc.textureCache.getTextureForKey('res/hero.png');
        cc.log('Hero texture size:', tex.getContentSize().width, 'x', tex.getContentSize().height);

        // Transition to game
        cc.director.runScene(new GameScene());
    }
}
```

Preloading via `cc.textureCache.addImage` ensures that creating sprites later with `new cc.Sprite(path)` is instant since the texture is already in GPU memory.
